local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxWorldCtrl:LxBaseCtrl
local LxWorldCtrl = classX("LxWorldCtrl", LxBaseCtrl)

function LxWorldCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
    ---@type LWorld
    self.curWorld = nil
    ---@type boolean
    self.isInWorld = false
    ---@type boolean
    self.isWorldLoading = false
    ---@type number
    self.tickSecondTime = 1
    ---@type number 自动打开实体UI的坐标
    self.autoOpenUIGridX = -1
    self.autoOpenUIGridZ = -1
end
function LxWorldCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end
--- 召唤大地图怪物
---@param type number 召唤怪对应的玩法类型(0,1)
---@param typeRefId number 配置表id
---@param monsterRefId number 世界怪物表id
function LxWorldCtrl:GoCallMonster(type, typeRefId, monsterRefId)
    self:GoWorld({
        callMonsterData = {
            type = type,
            typeRefId = typeRefId,
            monsterRefId = monsterRefId
        }
    })
end
--- 前往瞭望塔时间点
---@param watchTowerEventObj LxWatchTowerEventObj
function LxWorldCtrl:GoWatchTowerEvent(watchTowerEventObj)
    self:GoWorld({
        watchTowerEventObj = watchTowerEventObj
    })
end
--- params : gridX, gridZ, time, searchRefId
function LxWorldCtrl:GoWorld(params)
    --- 先判断是否已经生成城市据点
    local isOpen = CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.World, true)
    if not isOpen then
        return false
    end

    if MgrCenter.LevelMgr:IsInLevel(LevelNames.World) then
        if params then
            if params.gridX and params.gridZ then
                self.curWorld:SetGridPos(params.gridX, params.gridZ, params.time, params.callback)
            end
            if params.searchRefId and params.searchRefId > 0 then
                MgrCenter.PanelMgr:CloseAllOrdinaryView()
                ShowPanel(UiNames.WorldSearchView, {searchRefId = params.searchRefId, searchLevel = params.searchLevel})
            end
            if params.watchTowerEventObj then
                local gridX = params.watchTowerEventObj.gridX
                local gridZ = params.watchTowerEventObj.gridZ
                self.curWorld:JumpToGridPosLOD0(gridX, gridZ, 0.3, function()
                    self:OpenEntityMenuByPos(gridX, gridZ)
                end)
            end
            if params.callMonsterData then
                local type = params.callMonsterData.type
                local typeRefId = params.callMonsterData.typeRefId or 0
                local monsterRefId = params.callMonsterData.monsterRefId or 0
                HandlerCenter.World:WorldSummonMonsterGenerateReq(type, typeRefId, monsterRefId)
            end
        end
    else
        self.isInWorld = false
        self.isWorldLoading = true
        local gridX, gridZ = ModuleCenter.Role:GetMyGridPos()
        if params and params.gridX and params.gridZ then
            gridX = params.gridX
            gridZ = params.gridZ
        end
        local serverId = ModuleCenter.Login:GetLoginServerId()
        local newParams = {
            mapName = "WorldMap",
            serverId = serverId,
            gridX = gridX,
            gridZ = gridZ,
            searchRefId = params and params.searchRefId,
            searchLevel = params and params.searchLevel,
            watchTowerEventObj = params and params.watchTowerEventObj,
            callMonsterData = params and params.callMonsterData
        }
        MgrCenter.LevelMgr:LoadLevel(LevelNames.World, newParams, {loadUIName = UiNames.Interlude, isManuClose = true})
    end
end

function LxWorldCtrl:ExitWorld(params)
    self.isInWorld = false
    self.isWorldLoading = false
    self:RemoveMsgHandlerList()
    self:RemoveEventHandlerList()
    CtrlCenter.Main:GoHome()
end
---@return LWorld
function LxWorldCtrl:GetCurWorld()
    if not self.curWorld then
        local serverId = ModuleCenter.Login:GetLoginServerId()
        self.curWorld = MgrCenter.WorldMgr:GetWorld(serverId)
    end
    return self.curWorld
end
-----------------------------------------------------------------
function LxWorldCtrl:OnEnterWorld(mapTrans, params)
    self.isInWorld = true
    self.isWorldLoading = false
    self.autoOpenUIGridX = -1
    self.autoOpenUIGridZ = -1
    self:InitEvents()
    local serverId = params and params.serverId or ModuleCenter.Login:GetLoginServerId()
    local gridX = params and params.gridX
    local gridZ = params and params.gridZ
    local searchRefId = params and params.searchRefId
    local searchLevel = params and params.searchLevel
    if params.watchTowerEventObj then
        local watchTowerEventObj = params.watchTowerEventObj
        gridX = watchTowerEventObj.gridX
        gridZ = watchTowerEventObj.gridZ
        self.autoOpenUIGridX = gridX
        self.autoOpenUIGridZ = gridZ
    end
    self.curWorld = MgrCenter.WorldMgr:GetWorld(serverId)
    ModuleCenter.World:EnterWorld(self.curWorld)
    self.curWorld:EnterWorld(mapTrans, gridX, gridZ)
    --- 处理召唤怪物
    if params.callMonsterData then
        local type = params.callMonsterData.type
        local typeRefId = params.callMonsterData.typeRefId or 0
        local monsterRefId = params.callMonsterData.monsterRefId or 0
        HandlerCenter.World:WorldSummonMonsterGenerateReq(type, typeRefId, monsterRefId)
    end
    --- Open World UI
    ShowPanel(UiNames.WorldHUD)
    ShowPanel(UiNames.MainBottom, {isOutCity = true})
    ShowPanel(UiNames.WorldMain)
    if searchRefId and searchRefId > 0 then
        ShowPanel(UiNames.WorldSearchView, {searchRefId = searchRefId, searchLevel = searchLevel})
    end
    --- Start Time
    self:StartTimer("WorldTick", 0, true, -1, function() self:OnUpdate() end)
    self:AddEventHandler(EventNames.NET_RECONNECTED, self.OnReconnected, self)
end

function LxWorldCtrl:OnExitWorld(params)
    self.isInWorld = false
    self.isWorldLoading = false
    self:StopTimer("WorldTick")
    if self.curWorld then
        self.curWorld:ExitWorld()
    end
    ModuleCenter.World:BackMyWorld()
    self:RemoveEventHandlerList()
end

function LxWorldCtrl:OnReconnected()
    if self.curWorld then
        self.curWorld:RefreshData()
    end
end

function LxWorldCtrl:SetGuideReady(ready)
    self._guideReady = ready
end
function LxWorldCtrl:IsGuideReady()
    return self._guideReady
end
-----------------------------------------------------------------
function LxWorldCtrl:OnUpdate()
    local deltaTime = Time.deltaTime
    if self.curWorld then
        self.curWorld:OnUpdate(deltaTime)
    end
    self.tickSecondTime = self.tickSecondTime - deltaTime
    if self.tickSecondTime <= 0 then
        self.tickSecondTime = 1
        self:OnTickSecond()
    end
end
function LxWorldCtrl:OnTickSecond()
    if ModuleCenter.World.isMarchAlarm then
        local serverTime = GetTimestamp()
        ---@type table<string, MarchAlarmObj>
        local marchAlarmMap = ModuleCenter.World:GetMarchAlarmsMap()
        for marchId, marchAlarmObj in pairs(marchAlarmMap) do
            if serverTime >= marchAlarmObj.endTime then
                ModuleCenter.World:RemoveMarchAlarm(marchId)
                FireEvent(EventNames.WORLD_MARCH_ALARM_UPDATE)
                break
            end
        end
    end
end
-----------------------------------------------------------------
--- Event
function LxWorldCtrl:InitEvents()
    self:AddEventHandler(EventNames.WATCH_TOWER_UPDATE_INFO, self.RefreshWatchTowerEntity, self)
    self:AddEventHandler(EventNames.WATCH_TOWER_UPDATE_EVENT, self.RefreshWatchTowerEntity, self)
    self:AddEventHandler(EventNames.WATCH_TOWER_REMOVE_EVENT, self.RefreshWatchTowerEntity, self)
    self:AddMsgHandler(LxProtoIds.WorldViewportResp, self.OnWorldViewportResp, self)
end
function LxWorldCtrl:RefreshWatchTowerEntity()
    if self.curWorld then
        self.curWorld:ReloadWatchTowerEntity()
    end
end
function LxWorldCtrl:OnWorldViewportResp()
    --- 如果是瞭望塔事件，自动打开实体菜单
    if self.autoOpenUIGridX >= 0 and self.autoOpenUIGridZ >= 0 then
        local gridX = self.autoOpenUIGridX
        local gridZ = self.autoOpenUIGridZ
        self.autoOpenUIGridX = -1
        self.autoOpenUIGridZ = -1
        self:OpenEntityMenuByPos(gridX, gridZ)
    end
end
