--- UI
function LxWorldCtrl:OpenFormationHeroView(params)
    ShowPanel(UiNames.WorldFormationHero, params)
end
function LxWorldCtrl:OpenEntityMenu(params)
    ShowPanel(UiNames.WorldEntityMenu, params)
end
function LxWorldCtrl:OpenEntityMenuByPos(gridX, gridZ)
    if self.curWorld then
        ---@type LWorldEntityBase
        local entityObj = self.curWorld:SelectGridPos(gridX, gridZ)
        if entityObj then
            local viewGridX, viewGridZ = entityObj:GetViewGridPos()
            if viewGridX ~= gridX or viewGridZ ~= gridZ then
                self.curWorld:JumpToGridPosLOD0(viewGridX, viewGridZ, 0.1, function()
                    self.curWorld:SelectGridPos(gridX, gridZ)
                    self:OpenEntityMenu({entityObj = entityObj, gridX = entityObj.gridX, gridZ = entityObj.gridZ})
                end)
            else
                self:OpenEntityMenu({entityObj = entityObj, gridX = entityObj.gridX, gridZ = entityObj.gridZ})
            end
        end
    end
end
function LxWorldCtrl:CheckOpenEntityMenuByPos(gridX, gridZ)
    local entityObj = self.curWorld:SelectGridPos(gridX, gridZ)
    if entityObj then
        self:OpenEntityMenuByPos(gridX, gridZ)
    else
        self.autoOpenUIGridX = gridX
        self.autoOpenUIGridZ = gridZ
    end
end
function LxWorldCtrl:OpenEmptyGridMenu(params)
    ShowPanel(UiNames.WorldEmptyMenu, params)
end
function LxWorldCtrl:OpenScoutTips(params)
    ShowPanel(UiNames.WorldScoutTips, params)
end
function LxWorldCtrl:OpenSearchView()
    ShowPanel(UiNames.WorldSearchView)
end
function LxWorldCtrl:OpenMarchInfoView(roleId, marchId)
    ShowPanel(UiNames.WorldMarchInfo, {roleId = roleId, marchId = marchId})
end
